import { syncBashDispatcher } from '../../pretool/bash/sync-bash-dispatcher.js';
import { dangerousCommandBlocker } from '../../pretool/bash/dangerous-command-blocker.js';
import { compoundCommandValidator } from '../../pretool/bash/compound-command-validator.js';
import { unifiedBashAdvisoryDispatcher } from '../../pretool/bash/unified-advisory-dispatcher.js';
import { gitValidator } from '../../pretool/bash/git-validator.js';
import { issueReferenceChecker } from '../../pretool/bash/issue-reference-checker.js';
import { ghLabelEnforcer } from '../../pretool/bash/gh-label-enforcer.js';
import { ghMilestoneEnforcer } from '../../pretool/bash/gh-milestone-enforcer.js';
import { logHook } from '../../lib/common.js';

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

function createBashInput(command: string, overrides: Partial<HookInput> = {}): HookInput {
  return {
    tool_name: 'Bash',
    session_id: 'test-session-123',
    project_dir: '/test/project',
    tool_input: { command },
    ...overrides,
  };
}

function makeBlockResult(reason: string): HookResult {
  return {
    continue: false,
    stopReason: reason,
    hookSpecificOutput: {
      hookEventName: 'PreToolUse',
      permissionDecision: 'deny',
      permissionDecisionReason: reason,
    },
  };
}

function makeContextResult(context: string): HookResult {
  return {
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: { additionalContext: context, hookEventName: 'PreToolUse' },
  };
}

function makeUpdatedInputResult(updatedInput: Record<string, unknown>): HookResult {
  return {
    continue: true,
    suppressOutput: true,
    hookSpecificOutput: { hookEventName: 'PreToolUse', updatedInput },
  };
}

// ---------------------------------------------------------------------------
// Tests
// ---------------------------------------------------------------------------

describe('sync-bash-dispatcher', () => {
  beforeEach(() => {
    // resetAllMocks resets mock implementations back to their vi.mock() defaults,
    // preventing bleed-over from tests that override implementations (e.g., block scenarios)
    vi.resetAllMocks();
    // Re-establish default passing implementations after reset
    vi.mocked(dangerousCommandBlocker).mockReturnValue({ continue: true, suppressOutput: true });
    vi.mocked(compoundCommandValidator).mockReturnValue({ continue: true, suppressOutput: true });
    vi.mocked(gitValidator).mockReturnValue({ continue: true, suppressOutput: true });
    vi.mocked(issueReferenceChecker).mockReturnValue({ continue: true, suppressOutput: true });
    vi.mocked(ghLabelEnforcer).mockReturnValue({ continue: true, suppressOutput: true });
    vi.mocked(ghMilestoneEnforcer).mockReturnValue({ continue: true, suppressOutput: true });
    vi.mocked(unifiedBashAdvisoryDispatcher).mockReturnValue({ continue: true, suppressOutput: true });
  });

  // -------------------------------------------------------------------------
  // All hooks pass — silent result
  // -------------------------------------------------------------------------

  describe('all hooks pass silently', () => {
    it('returns silent success when all hooks are silent', () => {
      const input = createBashInput('git status');
      const result = syncBashDispatcher(input);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    it('calls all 7 hooks exactly once', () => {
      const input = createBashInput('npm run build');
      syncBashDispatcher(input);

      expect(dangerousCommandBlocker).toHaveBeenCalledWith(input);
      expect(compoundCommandValidator).toHaveBeenCalledWith(input);
      expect(gitValidator).toHaveBeenCalledWith(input);
      expect(issueReferenceChecker).toHaveBeenCalledWith(input);
      expect(ghLabelEnforcer).toHaveBeenCalledWith(input);
      expect(ghMilestoneEnforcer).toHaveBeenCalledWith(input);
      expect(unifiedBashAdvisoryDispatcher).toHaveBeenCalledWith(input);
    });
  });

  // -------------------------------------------------------------------------
  // Short-circuit on block
  // -------------------------------------------------------------------------

  describe('short-circuit on first block', () => {
    it('returns block result immediately when dangerous-command-blocker blocks', () => {
      const blockResult = makeBlockResult('rm -rf / is dangerous');
      vi.mocked(dangerousCommandBlocker).mockReturnValue(blockResult);

      const input = createBashInput('rm -rf /');
      const result = syncBashDispatcher(input);

      expect(result.continue).toBe(false);
      expect(result.stopReason).toBe('rm -rf / is dangerous');
    });

    it('does not call later hooks after Phase 1 block', () => {
      vi.mocked(dangerousCommandBlocker).mockReturnValue(makeBlockResult('blocked'));

      const input = createBashInput('rm -rf /');
      syncBashDispatcher(input);

      expect(compoundCommandValidator).not.toHaveBeenCalled();
      expect(gitValidator).not.toHaveBeenCalled();
      expect(ghLabelEnforcer).not.toHaveBeenCalled();
      expect(unifiedBashAdvisoryDispatcher).not.toHaveBeenCalled();
    });

    it('returns block result immediately when compound-command-validator blocks', () => {
      const blockResult = makeBlockResult('compound commands not allowed');
      vi.mocked(compoundCommandValidator).mockReturnValue(blockResult);

      const input = createBashInput('rm -rf . && exit');
      const result = syncBashDispatcher(input);

      expect(result.continue).toBe(false);
    });

    it('does not call Phase 3 advisory after Phase 2 git-validator block', () => {
      vi.mocked(gitValidator).mockReturnValue(makeBlockResult('git: direct push to main blocked'));

      const input = createBashInput('git push origin main --force');
      syncBashDispatcher(input);

      expect(unifiedBashAdvisoryDispatcher).not.toHaveBeenCalled();
    });

    it('logs short-circuit message when block occurs', () => {
      vi.mocked(dangerousCommandBlocker).mockReturnValue(makeBlockResult('blocked'));

      const input = createBashInput('rm -rf /');
      syncBashDispatcher(input);

      expect(logHook).toHaveBeenCalledWith(
        'sync-bash-dispatcher',
        expect.stringContaining('short-circuiting'),
      );
    });
  });

  // -------------------------------------------------------------------------
  // Context merging
  // -------------------------------------------------------------------------

  describe('context merging', () => {
    it('merges context from multiple passing hooks', () => {
      vi.mocked(ghLabelEnforcer).mockReturnValue(makeContextResult('Add a --label flag'));
      vi.mocked(ghMilestoneEnforcer).mockReturnValue(makeContextResult('Consider --milestone'));

      const input = createBashInput('gh issue create --title "Test"');
      const result = syncBashDispatcher(input);

      expect(result.continue).toBe(true);
      const ctx = result.hookSpecificOutput?.additionalContext as string;
      expect(ctx).toContain('Add a --label flag');
      expect(ctx).toContain('Consider --milestone');
    });

    it('separates merged contexts with ---', () => {
      vi.mocked(ghLabelEnforcer).mockReturnValue(makeContextResult('Context A'));
      vi.mocked(ghMilestoneEnforcer).mockReturnValue(makeContextResult('Context B'));

      const input = createBashInput('gh issue create --title "Test"');
      const result = syncBashDispatcher(input);

      const ctx = result.hookSpecificOutput?.additionalContext as string;
      expect(ctx).toContain('---');
    });

    it('returns single context without separator when only one hook has context', () => {
      vi.mocked(ghLabelEnforcer).mockReturnValue(makeContextResult('Only this advice'));

      const input = createBashInput('gh issue create --title "Test"');
      const result = syncBashDispatcher(input);

      const ctx = result.hookSpecificOutput?.additionalContext as string;
      expect(ctx).toContain('Only this advice');
    });

    it('returns silent success when no hooks produce context', () => {
      const input = createBashInput('git status');
      const result = syncBashDispatcher(input);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toBeUndefined();
    });
  });

  // -------------------------------------------------------------------------
  // updatedInput propagation
  // -------------------------------------------------------------------------

  describe('updatedInput propagation', () => {
    it('propagates updatedInput from a passing hook', () => {
      vi.mocked(unifiedBashAdvisoryDispatcher).mockReturnValue(
        makeUpdatedInputResult({ command: 'git status', timeout: 30000 }),
      );

      const input = createBashInput('git status');
      const result = syncBashDispatcher(input);

      expect(result.hookSpecificOutput?.updatedInput).toEqual({ command: 'git status', timeout: 30000 });
    });

    it('merges updatedInput + context together when both present', () => {
      vi.mocked(ghLabelEnforcer).mockReturnValue(makeContextResult('Label advice'));
      vi.mocked(unifiedBashAdvisoryDispatcher).mockReturnValue(
        makeUpdatedInputResult({ command: 'gh issue create', timeout: 5000 }),
      );

      const input = createBashInput('gh issue create --title "Test" --label bug');
      const result = syncBashDispatcher(input);

      expect(result.hookSpecificOutput?.updatedInput).toBeDefined();
      const ctx = result.hookSpecificOutput?.additionalContext as string;
      expect(ctx).toContain('Label advice');
    });
  });

  // -------------------------------------------------------------------------
  // Error isolation
  // -------------------------------------------------------------------------

  describe('error isolation', () => {
    it('continues when a non-blocking hook throws', () => {
      vi.mocked(ghLabelEnforcer).mockImplementation(() => {
        throw new Error('unexpected crash in gh-label-enforcer');
      });

      const input = createBashInput('git status');
      const result = syncBashDispatcher(input);

      // Dispatcher should not crash
      expect(result).toBeDefined();
      expect(result.continue).toBe(true);
    });

    it('logs warning when a hook throws', () => {
      vi.mocked(ghMilestoneEnforcer).mockImplementation(() => {
        throw new Error('crash');
      });

      const input = createBashInput('git status');
      syncBashDispatcher(input);

      expect(logHook).toHaveBeenCalledWith(
        'sync-bash-dispatcher',
        expect.stringContaining('gh-milestone-enforcer failed'),
        'warn',
      );
    });

    it('continues calling subsequent hooks after one throws', () => {
      vi.mocked(gitValidator).mockImplementation(() => {
        throw new Error('git validator crashed');
      });

      const input = createBashInput('git status');
      syncBashDispatcher(input);

      // gh-label-enforcer comes after git-validator — should still run
      expect(ghLabelEnforcer).toHaveBeenCalled();
    });

    it('handles non-Error throws gracefully', () => {
      vi.mocked(dangerousCommandBlocker).mockImplementation(() => {
        throw 'string error'; // eslint-disable-line no-throw-literal
      });

      const input = createBashInput('git status');
      expect(() => syncBashDispatcher(input)).not.toThrow();
    });
  });

  // -------------------------------------------------------------------------
  // Phase ordering
  // -------------------------------------------------------------------------

  describe('phase ordering', () => {
    it('calls dangerous-command-blocker before compound-command-validator', () => {
      const order: string[] = [];
      vi.mocked(dangerousCommandBlocker).mockImplementation(() => { order.push('dangerous'); return { continue: true, suppressOutput: true }; });
      vi.mocked(compoundCommandValidator).mockImplementation(() => { order.push('compound'); return { continue: true, suppressOutput: true }; });

      syncBashDispatcher(createBashInput('git status'));

      expect(order.indexOf('dangerous')).toBeLessThan(order.indexOf('compound'));
    });

    it('calls git-validator before gh-label-enforcer', () => {
      const order: string[] = [];
      vi.mocked(gitValidator).mockImplementation(() => { order.push('git-validator'); return { continue: true, suppressOutput: true }; });
      vi.mocked(ghLabelEnforcer).mockImplementation(() => { order.push('gh-label-enforcer'); return { continue: true, suppressOutput: true }; });

      syncBashDispatcher(createBashInput('git commit'));

      expect(order.indexOf('git-validator')).toBeLessThan(order.indexOf('gh-label-enforcer'));
    });

    it('calls all Phase 2 hooks before advisory dispatcher (Phase 3)', () => {
      const order: string[] = [];
      vi.mocked(ghMilestoneEnforcer).mockImplementation(() => { order.push('gh-milestone'); return { continue: true, suppressOutput: true }; });
      vi.mocked(unifiedBashAdvisoryDispatcher).mockImplementation(() => { order.push('advisory'); return { continue: true, suppressOutput: true }; });

      syncBashDispatcher(createBashInput('git status'));

      expect(order.indexOf('gh-milestone')).toBeLessThan(order.indexOf('advisory'));
    });
  });
});
